package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.BasisJaarWedde;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.RekenControleCode;
import lombok.AllArgsConstructor;
import lombok.Builder;
import org.apache.commons.lang.StringUtils;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.List;
import java.util.stream.Collectors;

import static be.schaubroeck.lpb.tools.enumtypes.Konstanten.KST_INDEX;

@AllArgsConstructor
@Builder
public class FlexiJobsControleOndergrens {

    private static final int FLEXI_LOON_CODE = 22;
    private static final BigDecimal FACTOR_BOVENGRENS = new BigDecimal("1.5");
    private static final LocalDate GRENS_NIEUWE_REGEL = new LocalDate(2024, 1, 1);

    private final ConstantManager constantManager;
    private final PersoonsDataManager dataManager;
    private final RegulManager regulManager;
    private final BerekenWeddeSchaal berekenWeddeSchaal;
    private final FlexiJobsUtil flexiJobsUtil;

    public void check(Opdracht opdracht, RekenTijd rekenTijd) {
        if (flexiJobsUtil.isFlexiJob(opdracht, rekenTijd)) {
            Money onderGrens = bepaalOnderGrensBedrag(opdracht, rekenTijd);

            List<NlpPrestatie> prestaties =
                    dataManager.findPrestaties(opdracht, rekenTijd.eindDatum).stream().filter(x -> x.getCode() == FLEXI_LOON_CODE).collect(Collectors.toList());

            if (rekenTijd.eindDatum.isBefore(GRENS_NIEUWE_REGEL)) {
                checkOndergrensOld(opdracht, prestaties, onderGrens);
            } else if (!prestaties.isEmpty()) {
                Money totaalFlexiLoon = berekenTotaalFlexiLoon(prestaties);
                BigDecimal totaalAantalUren = bepaalTotaalAantalUren(prestaties);
                Money uurLoon = totaalAantalUren.signum() != 0 ? totaalFlexiLoon.divide(totaalAantalUren).round(2) : Money.ZERO;
                Money bovenGrens = onderGrens.multiply(FACTOR_BOVENGRENS);
                checkOndergrens(opdracht, onderGrens, uurLoon);
                checkBovengrens(opdracht, bovenGrens, uurLoon);
            }
        }
    }

    private void checkOndergrensOld(Opdracht opdracht, List<NlpPrestatie> prestaties, Money grens) {
        List<NlpPrestatie> prestatiesOnderGrens = prestaties.stream().filter(x -> checkPrestatieOnderGrensOld(x, grens)).collect(Collectors.toList());
        if (!prestatiesOnderGrens.isEmpty()) {
            regulManager.addProtoWaarschuwing(opdracht, RekenControleCode.GRENS_FLEXI_LOON, getOmschrijvingTeLaagOud(prestaties, grens));
        }
    }

    private void checkOndergrens(Opdracht opdracht, Money grens, Money uurLoon) {
        if (uurLoon.compareTo(grens) < 0) {
            regulManager.doRegulException(opdracht, Regulkode.FOUT_BEGRENZING_FLEXILOON_LAAG, getOmschrijvingTeLaag(grens, uurLoon));
        }
    }

    private void checkBovengrens(Opdracht opdracht, Money grens, Money uurLoon) {
        if (uurLoon.compareTo(grens) > 0) {
            regulManager.addProtoWaarschuwing(opdracht, RekenControleCode.GRENS_FLEXI_LOON, getOmschrijvingTeHoog(grens, uurLoon));
        }
    }

    private Money berekenTotaalFlexiLoon(List<NlpPrestatie> prestaties) {
        return prestaties.stream().map(FlexiJobsControleOndergrens::berekenBedrag).reduce(Money.ZERO, Money::add);
    }

    private BigDecimal bepaalTotaalAantalUren(List<NlpPrestatie> prestaties) {
        return prestaties.stream()
                .filter(x -> x.getAard().equals(AardKodeExt.D_KODE_EXT.getCode()))
                .map(NlpPrestatie::getAantal)
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private String getOmschrijvingTeLaagOud(List<NlpPrestatie> prestaties, Money grens) {
        return getOmschrijvingTeLaag(grens, prestaties.get(0).getY());
    }

    private static String getOmschrijvingTeLaag(Money grens, Money uurloon) {
        return "uurloon flexiloon te laag, bedrag is " + uurloon + ", ondergrens is " + grens;
    }


    private static String getOmschrijvingTeHoog(Money grens, Money uurloon) {
        return "uurloon flexiloon te hoog, bedrag is " + uurloon + ", bovengrens is " + grens;
    }

    private Money bepaalOnderGrensBedrag(Opdracht opdracht, RekenTijd rekenTijd) {
        if (GRENS_NIEUWE_REGEL.isBefore(rekenTijd.eindDatum)) {
            Money basisBedrag = bepaalBasisBedrag(opdracht, rekenTijd);
            Integer werkUrenJaar = constantManager.getByCodeDatum(Konstanten.KST_WERKUREN_JAAR, rekenTijd.eindDatum).getInteger();
            return basisBedrag.divide(werkUrenJaar).round(2);
        } else {
            return constantManager.getByCodeDatum(Konstanten.KST_ONDERGRENS_FLEXI_LOON, rekenTijd.eindDatum).getMoney();
        }
    }

    private Money bepaalBasisBedrag(Opdracht opdracht, RekenTijd rekenTijd) {
        if (schaalIsAanwezig(opdracht)) {
            return bepaalTrapZeroVanSchaal(opdracht, rekenTijd);
        } else {
            Money basisBedrag = constantManager.getByCodeDatum(Konstanten.KST_GMMI, rekenTijd.eindDatum).getMoney();
            return basisBedrag.multiply(RekenTools.TWELVE);
        }
    }

    private static boolean schaalIsAanwezig(Opdracht opdracht) {
        Opper laatsteGegevens = RekenTools.getLaatsteGegevens(opdracht.getOpperSlices());
        BasisJaarWedde basisJaarWedde = laatsteGegevens.getBasisJaarWedde();
        return basisJaarWedde.getInfoBron() == 1 && !StringUtils.isBlank(basisJaarWedde.getInfoInternNr()) && basisJaarWedde.getInfoVersie() != null &&
                basisJaarWedde.getInfoVersie() != 0;
    }

    private Money bepaalTrapZeroVanSchaal(Opdracht opdracht, RekenTijd rekenTijd) {
        Opper laatsteGegevens = RekenTools.getLaatsteGegevens(opdracht.getOpperSlices());
        String internnr = laatsteGegevens.getBasisJaarWedde().getInfoInternNr();
        int versie = laatsteGegevens.getBasisJaarWedde().getInfoVersie();
        BigDecimal index = constantManager.getByCodeDatum(KST_INDEX, rekenTijd.eindDatum).getProcentFactor();
        return berekenWeddeSchaal.berekenTrap(internnr, versie, 0).multiply(index);
    }

    private static boolean checkPrestatieOnderGrensOld(NlpPrestatie prestatie, Money onderGrens) {
        return prestatie.getY().compareTo(onderGrens) < 0;
    }

    private static Money berekenBedrag(NlpPrestatie prestatie) {
        return prestatie.getY().multiply(prestatie.getX());
    }
}
